from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["mobile-permission-relay-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>Mobile Permission Relay</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e;--warn:#f59e0b;--bad:#ef4444}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:8px}button,input,textarea,select{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}button.bad{background:linear-gradient(135deg,#ef4444,#f97316)}textarea{width:100%;min-height:90px}.req{border-left:4px solid var(--warn);padding:9px 10px;background:#081226;border-radius:14px}.sensitive{border-left-color:var(--bad)}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>Mobile Permission Relay + Driver Voice</h1><p class="muted">PC espera autorização do telemóvel. Se não houver rede, fica em espera e reenvia. Em condução: voz curta, sem toque.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/mobile-approval-cockpit-v2'" class="dark">Approvals</button><button onclick="dashboard()">Dashboard</button><button onclick="poll()">Pendentes</button></div></section><section class="panel"><h2>Criar pedido teste</h2><input id="title" style="width:100%" value="Autorizar continuação da tarefa God Mode"/><textarea id="body">O PC precisa de autorização para continuar a próxima tarefa segura. Podes aprovar por voz ou botão.</textarea><div class="grid"><select id="type"><option>approval</option><option>login_manual</option><option>sensitive_fill</option><option>pause_continue</option><option>blocking_decision</option><option>credential_prompt</option></select><select id="priority"><option>medium</option><option>high</option><option>critical</option><option>low</option></select></div><div class="buttons"><button onclick="createReq(false)">Criar aprovação</button><button onclick="createReq(true)">Criar pedido sensível</button></div></section><section class="panel"><h2>Responder / Voz</h2><input id="reqId" style="width:100%" placeholder="permission-request-..."/><textarea id="note">Resposta via cockpit.</textarea><div class="buttons"><button onclick="decide('approved')">OK / Aprovar</button><button class="bad" onclick="decide('rejected')">Rejeitar</button><button onclick="voice('aprovar continua')">Voz: continuar</button><button onclick="offline()">Sem rede / espera</button><button onclick="resend()">Reenviar</button></div></section><section class="panel"><h2>Pendentes</h2><div id="items" class="grid"></div></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s??'').replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){const items=x?.permission_requests||x?.pending||x?.recent_requests||x?.permission_request?[x.permission_request]:x?.dashboard?.pending||[];qs('#items').innerHTML=(Array.isArray(items)?items:[]).slice(0,24).map(it=>`<div class="req ${it.requires_sensitive_input?'sensitive':''}" onclick="qs('#reqId').value='${esc(it.permission_request_id)}'"><b>${esc(it.status)}</b> ${esc(it.request_type)}<br>${esc(it.title)}<br><span class="muted">${esc(it.driver_safe_summary||it.permission_request_id)}</span></div>`).join('')}async function dashboard(){show(await api('/api/mobile-permission-relay/dashboard'))}async function poll(){show(await api('/api/mobile-permission-relay/poll?limit=100'))}async function createReq(sensitive){show(await api('/api/mobile-permission-relay/create-request',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title:qs('#title').value,body:qs('#body').value,request_type:qs('#type').value,priority:qs('#priority').value,requires_sensitive_input:sensitive,form_schema:sensitive?[{name:'credential_value',label:'Credencial / código',type:'password',required:true,sensitive:true}]:[],wait_for_response:true})}))}async function decide(decision){show(await api('/api/mobile-permission-relay/decide',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({permission_request_id:qs('#reqId').value,decision,operator_note:qs('#note').value,form_values:{credential_value:'provided-on-device-not-stored'}})}))}async function voice(t){show(await api('/api/mobile-permission-relay/voice-event',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({permission_request_id:qs('#reqId').value,transcript:t,intent:t,driving_mode:true})}))}async function offline(){show(await api('/api/mobile-permission-relay/mark-offline-wait',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({permission_request_id:qs('#reqId').value,reason:'phone_offline_or_tunnel'})}))}async function resend(){show(await api('/api/mobile-permission-relay/mark-resend-pending',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({permission_request_id:qs('#reqId').value,reason:'resend_after_offline'})}))}dashboard()</script></body></html>
"""


@router.get('/app/mobile-permission-relay', response_class=HTMLResponse)
async def mobile_permission_relay_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/driver-voice-permissions', response_class=HTMLResponse)
async def driver_voice_permissions_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
